class Solution {
public:
    int getMinSwaps(string num, int k) {
        int n = num.size();
        vector<int> count(10);
        for (char c : num) count[c - '0']++;
        vector<int> nums(n);
        for (int i = 0; i < n; i++) nums[i] = num[i] - '0';
        int res = 0;
        for (int i = 0; i < k; i++) {
            int min_idx = -1;
            for (int j = 0; j < n; j++) {
                if (nums[j] != 0 && (min_idx == -1 || nums[j] < nums[min_idx])) min_idx = j;
            }
            int min_val = nums[min_idx];
            nums[min_idx] = 0;
            int j = min_idx + 1;
            while (j < n && nums[j] != 0) j++;
            if (j == n) continue;
            int tmp = nums[j];
            for (int p = j; p > min_idx; p--) {
                nums[p] = nums[p - 1];
            }
            nums[min_idx] = tmp;
            res++;
        }
        return res;
    }
};
```

